class Solution:
    def minGroupsForValidAssignment(self, balls):
        from collections import Counter
        counts = list(Counter(balls).values())

        def min_boxes_for_size(c, s):
            # Independent DP: smallest number of parts, each of size s or s+1,
            # that sum exactly to c. Returns None if impossible.
            INF = float('inf')
            dp = [INF] * (c + 1)
            dp[0] = 0
            for x in range(1, c + 1):
                best = INF
                if x >= s and dp[x - s] + 1 < best:
                    best = dp[x - s] + 1
                if x >= s + 1 and dp[x - (s + 1)] + 1 < best:
                    best = dp[x - (s + 1)] + 1
                dp[x] = best
            return dp[c] if dp[c] != INF else None

        max_size = max(counts)
        for s in range(max_size, 0, -1):
            total = 0
            feasible = True
            for c in counts:
                m = min_boxes_for_size(c, s)
                if m is None:
                    feasible = False
                    break
                total += m
            if feasible:
                return total
        return len(counts)

