class Solution:
    def minGroupsForValidAssignment(self, balls):
        from collections import Counter
        counts = list(Counter(balls).values())
        min_freq = min(counts)
        for s in range(min_freq, 0, -1):
            total = 0
            feasible = True
            for c in counts:
                m = (c + s) // (s + 1)
                if m == 0:
                    m = 1
                if m * s > c:
                    feasible = False
                    break
                total += m
            if feasible:
                return total
        return len(counts)

