var minGroupsForValidAssignment = function(balls) {
    const freq = new Map();
    for (const b of balls) freq.set(b, (freq.get(b) || 0) + 1);
    const counts = Array.from(freq.values());
    const minFreq = Math.min(...counts);
    for (let s = minFreq; s >= 1; s--) {
        let total = 0;
        let feasible = true;
        for (const c of counts) {
            let m = Math.floor((c + s) / (s + 1));
            if (m === 0) m = 1;
            if (m * s > c) {
                feasible = false;
                break;
            }
            total += m;
        }
        if (feasible) return total;
    }
    return counts.length;
};
